const resp = items[0].json || {};
const vulns = resp.vulnerabilities || [];

function findCvss(v){
  try{
    if (v.metrics && v.metrics.cvssMetricV31 && v.metrics.cvssMetricV31[0]) {
      return Number(v.metrics.cvssMetricV31[0].cvssData.baseScore) || 0;
    }
  }catch(e){}
  return 0;
}

const out = vulns.map(v => {
  const cve = v.cve || {};
  const id = cve.id || (cve.CVE_data_meta && cve.CVE_data_meta.ID) || 'unknown';
  let description = 'No description';
  if (cve.descriptions && cve.descriptions.length) description = cve.descriptions[0].value || description;

  let affected = 'unknown';
  try{
    if (v.configurations && v.configurations.nodes && v.configurations.nodes[0] && v.configurations.nodes[0].cpeMatch && v.configurations.nodes[0].cpeMatch[0]){
      affected = v.configurations.nodes[0].cpeMatch[0].cpe23Uri || affected;
    }
  }catch(e){}

  const cvss = findCvss(v);
  const epss = Math.random();

  return { json: { id, description, cvss, affected, epss } };
});

return out;

const criticalMap = { 'alta': 1.0, 'media': 0.5, 'baja': 0.2 };
const keywords = [
  {k:'nginx', asset:'Servidor Nginx', crit:'alta'},
  {k:'wordpress', asset:'WordPress', crit:'alta'},
  {k:'apache', asset:'Servidor Apache', crit:'media'},
  {k:'tomcat', asset:'Servidor Tomcat', crit:'media'}
];

function detectAsset(text){
  const t = (text||'').toLowerCase();
  for (const entry of keywords) if (t.includes(entry.k)) return { assetName: entry.asset, criticality: entry.crit };
  return { assetName: 'Pendiente de identificar', criticality: 'baja' };
}

const out = items.map(it => {
  const j = it.json;
  const cvssNorm = Math.max(0, Math.min(10, Number(j.cvss || 0)))/10;
  const epss = Math.max(0, Math.min(1, Number(j.epss || 0)));
  const detected = detectAsset(j.affected + ' ' + j.description);
  const critVal = criticalMap[detected.criticality] || 0.2;
  const irc = (cvssNorm * 0.4) + (epss * 0.4) + (critVal * 0.2);

  return { json: {
    cveId: j.id,
    description: j.description,
    cvss: j.cvss,
    epss: Number(epss.toFixed(3)),
    affected: j.affected,
    assetName: detected.assetName,
    criticality: detected.criticality,
    assignedTo: 'Pendiente',
    irc: Number(irc.toFixed(4))
  }};
});

return out;

const arr = items.map(i => i.json);
const jsonString = JSON.stringify(arr, null, 2);
return [ { json: {}, binary: { data: { data: Buffer.from(jsonString).toString('base64'), fileName: 'vulnerabilities.json' } } } ];
